={{ (() => { const draft = { executionId: $json.executionId, sourceTitle: $json.sourceTitle, sourceLink: $json.sourceLink, postText: $json.postText, videoPrompt: $json.videoPrompt, sourceImageUrl: $json.sourceImageUrl, sourceVideoUrl: $json.sourceVideoUrl, generatedMediaPath: $json.generatedMediaPath, generatedMediaUrl: $json.generatedMediaUrl, generatedMediaName: $json.generatedMediaName }; return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>Sarah Nutri Video Review</title>
<style>
:root { color-scheme: dark; }
body { margin: 0; font-family: Inter, Arial, sans-serif; background: #0b1020; color: #e5e7eb; }
main { max-width: 860px; margin: 0 auto; padding: 20px 16px 48px; }
.card { background: #121933; border: 1px solid #243055; border-radius: 16px; padding: 16px; margin-bottom: 16px; box-shadow: 0 10px 30px rgba(0,0,0,.25); }
h1 { font-size: 24px; margin: 0 0 8px; }
h2 { font-size: 16px; margin: 0 0 12px; color: #93c5fd; }
p, a, label, textarea, button, pre { font-size: 15px; }
a { color: #7dd3fc; word-break: break-word; }
.preview { width: 100%; border-radius: 14px; background: #0f172a; overflow: hidden; min-height: 120px; display: flex; align-items: center; justify-content: center; }
.preview img, .preview video { width: 100%; max-height: 420px; object-fit: cover; display: block; }
.copy { white-space: pre-wrap; line-height: 1.55; }
textarea { width: 100%; min-height: 120px; border-radius: 12px; border: 1px solid #334155; background: #0f172a; color: #e5e7eb; padding: 12px; box-sizing: border-box; }
.actions { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 12px; }
button { border: 0; border-radius: 12px; padding: 14px 16px; font-weight: 700; cursor: pointer; }
button.approve { background: #22c55e; color: #08130c; }
button.reject { background: #ef4444; color: white; }
button:disabled { opacity: 0.6; cursor: wait; }
.status { margin-top: 12px; min-height: 22px; color: #cbd5e1; white-space: pre-wrap; line-height: 1.45; }
small { color: #94a3b8; display: block; margin-top: 8px; }
details { margin-top: 12px; }
summary { cursor: pointer; color: #93c5fd; }
@media (max-width: 640px) { .actions { grid-template-columns: 1fr; } main { padding: 14px 12px 36px; } }
</style>
</head>
<body>
<main>
<div class="card">
<h1>Sarah Nutri Video Review</h1>
<p>Review the draft, compare the source video with the Veo placeholder, then approve or reject with instructions.</p>
</div>
<div class="card">
<h2>Source</h2>
<p id="title" class="copy"></p>
<p><a id="sourceLink" href="#" target="_blank" rel="noreferrer">Open source</a></p>
</div>
<div class="card">
<h2>Source Media Preview</h2>
<div id="preview" class="preview"></div>
<small>The original source media stays the default post asset when it exists.</small>
</div>
<div class="card">
<h2>Veo Fallback (Inactive)</h2>
<div id="generatedPreview" class="preview"></div>
<small>Veo is inactive for now, so the source video remains the default review asset.</small>
</div>
<div class="card">
<h2>Draft Post</h2>
<pre id="postText" class="copy"></pre>
<details>
<summary>Show video prompt</summary>
<pre id="videoPrompt" class="copy"></pre>
</details>
</div>
<div class="card">
<h2>Decision</h2>
<label for="feedback">If rejecting, describe exactly what should change.</label>
<textarea id="feedback" placeholder="Example: make it more polemical, add more urgency, generate new media with a stronger emotional tone"></textarea>
<div class="actions">
<button class="approve" id="approveBtn">Approve</button>
<button class="reject" id="rejectBtn">Reject And Rewrite</button>
</div>
<div class="status" id="status"></div>
</div>
</main>
<script>
const draft = ${JSON.stringify(draft)};
const baseCallback = 'http://192.168.1.59:8080/webhook/sarah-nutri-video-approval';
const approveBtn = document.getElementById('approveBtn');
const rejectBtn = document.getElementById('rejectBtn');
document.getElementById('title').textContent = draft.sourceTitle || 'Untitled';
const link = document.getElementById('sourceLink');
link.href = draft.sourceLink || '#';
link.textContent = draft.sourceLink || 'No source link available';
document.getElementById('postText').textContent = draft.postText || '';
document.getElementById('videoPrompt').textContent = draft.videoPrompt || '';
const preview = document.getElementById('preview');
if (draft.sourceVideoUrl) {
  const video = document.createElement('video');
  video.src = draft.sourceVideoUrl;
  video.controls = true;
  video.playsInline = true;
  preview.appendChild(video);
} else if (draft.sourceImageUrl) {
  const img = document.createElement('img');
  img.src = draft.sourceImageUrl;
  img.alt = 'Source media preview';
  preview.appendChild(img);
} else {
  preview.textContent = 'No source media preview available.';
}
const generatedPreview = document.getElementById('generatedPreview');
const generatedCard = generatedPreview.parentElement;
if (draft.generatedMediaUrl || draft.generatedMediaPath) {
  const generatedAsset = (draft.generatedMediaUrl || draft.generatedMediaPath || '').toLowerCase();
  if (generatedAsset.endsWith('.mp4') || generatedAsset.endsWith('.webm') || generatedAsset.endsWith('.mov')) {
    const video = document.createElement('video');
    video.src = draft.generatedMediaUrl || draft.generatedMediaPath;
    video.controls = true;
    video.playsInline = true;
    generatedPreview.appendChild(video);
  } else {
    const img = document.createElement('img');
    img.src = draft.generatedMediaUrl || draft.generatedMediaPath;
    img.alt = 'AI generated fallback preview';
    generatedPreview.appendChild(img);
  }
  const note = document.createElement('small');
  note.textContent = draft.sourceVideoUrl ? 'The generated preview is available above.' : 'No source video was available, so the generated MP4 is the default approval asset.';
  generatedCard.appendChild(note);
} else {
  generatedPreview.textContent = 'No Veo fallback is available yet. Reject a draft to generate a new version.';
}
const statusEl = document.getElementById('status');
function setStatus(message) { statusEl.textContent = message; }
function setBusy(isBusy) {
  approveBtn.disabled = isBusy;
  rejectBtn.disabled = isBusy;
}
function selectedMediaChoice() {
  const selected = document.querySelector('input[name=\"mediaChoice\"]:checked');
  return selected ? selected.value : 'source';
}
async function sendDecision(action) {
  const feedback = document.getElementById('feedback').value.trim();
  if (action === 'reject' && !feedback) {
    setStatus('Add feedback before rejecting.');
    return;
  }
  setBusy(true);
  setStatus(action === 'approve' ? 'Approving and sending to Postiz...' : 'Rejecting and requesting a rewrite...');
  const url = new URL(baseCallback);
  url.searchParams.set('action', action);
  url.searchParams.set('executionId', draft.executionId);
  url.searchParams.set('mediaChoice', selectedMediaChoice());
  if (feedback) url.searchParams.set('feedback', feedback);
  try {
    const response = await fetch(url.toString(), { method: 'GET' });
    const payload = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(payload.message || 'Request failed');
    const message = payload.message || (action === 'approve' ? 'Approved.' : 'Rejected.');
    setStatus(message);
    if (action === 'approve') {
      rejectBtn.disabled = true;
    } else {
      setBusy(false);
    }
  } catch (error) {
    setBusy(false);
    setStatus(error.message || 'Request failed. Try again.');
  }
}
approveBtn.addEventListener('click', () => sendDecision('approve'));
rejectBtn.addEventListener('click', () => sendDecision('reject'));
</script>
</body>
</html>`; })() }}
